.oppexp {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --hairline: rgba(255,255,255,.06);
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  --success: var(--color-success, #36D399);
  --danger: var(--color-danger, #FF5A6E);
  --warning: #F6C453;
  --input-bg: var(--input-bg-color, #1B1B21);
  --input-border: var(--input-border-color, #2A2A32);
  container-type: inline-size;
  height: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}
.oppexp .oppexp-card, .oppexp .oppexp-search, .oppexp .oppexp-tbl, .oppexp .oppexp-th, .oppexp tbody td, .oppexp .oppexp-prob, .oppexp .oppexp-prob-track { box-sizing: border-box; }
.oppexp .oppexp-card {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  overflow: hidden;
}
.oppexp .oppexp-head {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  border-bottom: 1px solid var(--line);
}
.oppexp .oppexp-titles { display: flex; flex-direction: column; gap: 3px; margin-right: auto; }
.oppexp .oppexp-eyebrow {
  display: inline-flex;
  align-items: center;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--muted);
}
.oppexp .oppexp-eyebrow::before {
  content: "";
  width: 6px;
  height: 6px;
  margin-right: 8px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 9px -1px color-mix(in srgb, var(--accent) 70%, transparent);
}
.oppexp .oppexp-title {
  margin: 0;
  font: 800 18px/1.15 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
}
.oppexp .oppexp-tools { display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }
.oppexp .oppexp-count {
  font: 600 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .06em;
  text-transform: uppercase;
  color: var(--muted);
  font-variant-numeric: tabular-nums;
  padding: 5px 10px;
  border-radius: 999px;
  border: 1px solid var(--line);
  background: var(--surface-raised);
  white-space: nowrap;
}
.oppexp .oppexp-search {
  font: 500 13px/1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  min-width: 200px;
  padding: 9px 12px;
  border-radius: 10px;
  border: 1px solid var(--input-border);
  background: var(--input-bg);
  color: var(--ink);
  transition: border-color .15s ease, box-shadow .15s ease;
}
.oppexp .oppexp-search::placeholder { color: var(--muted); }
.oppexp .oppexp-search:hover { border-color: color-mix(in srgb, var(--accent) 30%, var(--input-border)); }
.oppexp .oppexp-search:focus-visible {
  outline: none;
  border-color: color-mix(in srgb, var(--accent) 55%, var(--input-border));
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--accent) 22%, transparent);
}
.oppexp .oppexp-tbl-wrap {
  flex: 1;
  min-height: 0;
  overflow-x: auto;
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}
.oppexp .oppexp-tbl {
  width: 100%;
  border-collapse: collapse;
  font: 500 13px/1.45 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}
.oppexp .oppexp-th {
  position: sticky;
  top: 0;
  z-index: 1;
  background: var(--surface);
  text-align: left;
  white-space: nowrap;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .05em;
  text-transform: uppercase;
  color: var(--muted);
  padding: 11px 14px;
  border-bottom: 1px solid var(--line);
  cursor: pointer;
  user-select: none;
  transition: color .12s ease;
}
.oppexp .oppexp-th.is-num { text-align: right; }
.oppexp .oppexp-th:hover { color: var(--ink); }
.oppexp .oppexp-th:focus-visible { outline: 2px solid var(--accent); outline-offset: -2px; }
.oppexp .oppexp-th:has(.oppexp-arrow.is-active) { color: var(--ink); box-shadow: inset 0 -2px 0 var(--accent); }
.oppexp .oppexp-arrow { margin-left: 6px; font-size: 10px; opacity: .5; }
.oppexp .oppexp-arrow.is-active { opacity: 1; color: var(--accent); }
.oppexp tbody td {
  padding: 10px 14px;
  border-top: 1px solid var(--hairline);
  color: var(--ink);
  white-space: nowrap;
  transition: background-color .12s ease;
}
.oppexp tbody td.is-num { text-align: right; font-variant-numeric: tabular-nums; }
.oppexp tbody tr:hover td { background: var(--surface-raised); }
.oppexp .oppexp-chip {
  display: inline-block;
  padding: 3px 9px;
  border-radius: 999px;
  font: 700 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .02em;
  border: 1px solid var(--line);
  background: var(--surface-raised);
  color: var(--ink);
  white-space: nowrap;
}
.oppexp .oppexp-chip.tone-won { background: var(--success); border-color: transparent; color: #0B0B0D; }
.oppexp .oppexp-chip.tone-lost { color: var(--danger); background: color-mix(in srgb, var(--danger) 16%, transparent); border-color: color-mix(in srgb, var(--danger) 38%, transparent); }
.oppexp .oppexp-chip.tone-active { color: var(--accent); background: color-mix(in srgb, var(--accent) 14%, transparent); border-color: color-mix(in srgb, var(--accent) 32%, transparent); }
.oppexp .oppexp-chip.tone-open { color: var(--muted); background: transparent; }
.oppexp .oppexp-prob { display: inline-flex; flex-direction: column; align-items: flex-end; gap: 4px; min-width: 70px; }
.oppexp .oppexp-prob-val { font-variant-numeric: tabular-nums; color: var(--ink); }
.oppexp .oppexp-prob-track { width: 100%; height: 4px; border-radius: 999px; background: rgba(255,255,255,.08); overflow: hidden; }
.oppexp .oppexp-prob-fill { display: block; height: 100%; border-radius: 999px; background: var(--accent); }
.oppexp .oppexp-prob-fill.tone-high { background: var(--success); }
.oppexp .oppexp-prob-fill.tone-mid { background: var(--warning); }
.oppexp .oppexp-prob-fill.tone-low { background: var(--danger); }
.oppexp .oppexp-empty {
  margin: 0;
  padding: 28px 16px;
  text-align: center;
  color: var(--muted);
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}
/* ---------- responsive: container-query first (block sizes to its own cell, not the viewport) ---------- */
@container (max-width: 720px) {
  .oppexp .oppexp-head { gap: 10px; }
}
@container (max-width: 640px) {
  .oppexp .oppexp-search { min-width: 0; flex: 1; }
  .oppexp tbody td, .oppexp .oppexp-th { padding-left: 10px; padding-right: 10px; }
}
@container (max-width: 560px) {
  .oppexp .oppexp-titles { margin-right: 0; flex: 1 1 100%; }
  .oppexp .oppexp-tools { width: 100%; }
  .oppexp .oppexp-count { order: 1; }
  .oppexp .oppexp-search { order: 2; flex: 1 1 100%; min-width: 0; }
}
/* ---------- touch targets >= 44px on coarse pointers (no container equivalent for pointer type) ---------- */
@media (pointer: coarse) {
  .oppexp .oppexp-search { min-height: 44px; }
  .oppexp .oppexp-th { padding-top: 15px; padding-bottom: 15px; }
  .oppexp tbody td { padding-top: 13px; padding-bottom: 13px; }
}
@media (prefers-reduced-motion: reduce) {
  .oppexp .oppexp-th, .oppexp .oppexp-search, .oppexp tbody td { transition: none; }
}
